#!/usr/bin/env bash
set -euo pipefail
ROOT="${1:-$PWD}"
if [[ ! -f "$ROOT/pyproject.toml" || ! -d "$ROOT/src/grid_world" ]]; then
  echo "ERROR: $ROOT is not the grid-world repository." >&2
  exit 1
fi
TMP="$(mktemp -d)"
base64 -d > "$TMP/scripts.zip" <<'GRID_WORLD_NEXT_ANALYSIS'

GRID_WORLD_NEXT_ANALYSIS
unzip -qo "$TMP/scripts.zip" -d "$ROOT"
rm -rf "$TMP"
chmod +x "$ROOT"/scripts/analyze_run_quality.py "$ROOT"/scripts/make_probe_views.py "$ROOT"/scripts/compare_probe_views.py "$ROOT"/scripts/run_next_analysis.sh
python -m py_compile "$ROOT"/scripts/analyze_run_quality.py "$ROOT"/scripts/make_probe_views.py "$ROOT"/scripts/compare_probe_views.py
echo "Next-analysis scripts installed."
echo "Run: cd $ROOT && RUN=runs/qwen25_7b_diverse5x5_1000 bash scripts/run_next_analysis.sh"
